// Function Overloading - Different Number of Parameters
#include <iostream>
using namespace std;

class Calculator {
public:
 // Overload 1: Add two numbers
 int add(int a, int b) {
 return a + b;
 }

 // Overload 2: Add three numbers
 int add(int a, int b, int c) {
 return a + b + c;
 }

 // Overload 3: Add two doubles
 double add(double a, double b) {
 return a + b;
 }
};

int main() {
 Calculator calc;
 cout << "Add(10, 20): " << calc.add(10, 20) << endl;
 cout << "Add(10, 20, 30): " << calc.add(10, 20, 30) << endl;
 cout << "Add(10.5, 20.5): " << calc.add(10.5, 20.5) << endl;
 return 0;
}

// Constructor Overloading
#include <iostream>
using namespace std;

class Box {
private:
 int length, width, height;

public:
 // Default Constructor
 Box() {
 length = width = height = 1;
 }

 // Parameterized Constructor
 Box(int l, int w, int h) {
 length = l;
 width = w;
 height = h;
 }

 // Copy Constructor
 Box(const Box& b) {
 length = b.length;
 width = b.width;
 height = b.height;
 }

 int volume() {
 return length * width * height;
 }
};

int main() {
 Box b1; // Calls default
 Box b2(2, 3, 4); // Calls parameterized
 Box b3(b2); // Calls copy constructor

 cout << "b1 volume: " << b1.volume() << endl;
 cout << "b2 volume: " << b2.volume() << endl;
 cout << "b3 volume: " << b3.volume() << endl;
 return 0;
}

// Ambiguity in Function Overloading
#include <iostream>
using namespace std;

void print(int x) {
 cout << "Integer: " << x << endl;
}

void print(double x) {
 cout << "Double: " << x << endl;
}

// This would cause ambiguity:
// void print(int x, int y = 0) {}
// void print(double x) {}

int main() {
 print(10); // Calls print(int) - exact match
 print(10.5); // Calls print(double) - exact match
 print('A'); // Ambiguous! 'A' can be int(65) or double(65.0)

 // Uncommenting below causes ambiguity error:
 // print(10, 20);

 return 0;
}

// const vs non-const Parameter Overloading
#include <iostream>
using namespace std;

class String {
private:
 char str[100];

public:
 String(const char* s) {
 strcpy(str, s);
 }

 // Overload for non-const reference - can modify
 char& getChar(int index) {
 cout << "Non-const version called" << endl;
 return str[index];
 }

 // Overload for const reference - read only
 const char& getChar(int index) const {
 cout << "Const version called" << endl;
 return str[index];
 }

 void display() {
 cout << str << endl;
 }
};

int main() {
 String s("Hello");
 char c = s.getChar(0); // Calls non-const version
 s.display();

 const String cs("World");
 char cc = cs.getChar(0); // Calls const version
 cs.display();

 return 0;
}

// Function Overloading - Different Parameter Order
#include <iostream>
using namespace std;

class Data {
public:
 // Overload 1: (int, double)
 void process(int a, double b) {
 cout << "process(int, double): " << a << ", " << b << endl;
 }

 // Overload 2: (double, int) - Different order!
 void process(double a, int b) {
 cout << "process(double, int): " << a << ", " << b << endl;
 }
};

int main() {
 Data d;
 d.process(10, 5.5); // Calls (int, double)
 d.process(5.5, 10); // Calls (double, int)
 d.process(10, 10); // Calls (int, double) - int preferred over double

 return 0;
}
